};

export default About;

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import FloatingCard from '../ui/FloatingCard';
import { Send, CheckCircle2, AlertCircle } from 'lucide-react';
import api from '../../services/api';

const Contact = () => {
  const [formData, setFormData] = useState({ name: '', email: '', message: '' });
  const [status, setStatus] = useState({ state: 'idle', msg: '' });

  const handleChange = (e) => setFormData({ ...formData, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus({ state: 'loading', msg: '' });
    try {
      await api.post('/contact', formData);
      setStatus({ state: 'success', msg: 'Message sent! Reaching out soon.' });
      setFormData({ name: '', email: '', message: '' });
    } catch (err) {
      setStatus({ state: 'error', msg: 'Failed to send message.' });
    }
  };

  return (
    <section id="contact" className="py-24 px-6 max-w-4xl mx-auto relative z-10">
      <FloatingCard className="!p-10 md:!p-16 neon-border group">
        <div className="absolute top-0 right-0 w-64 h-64 bg-pink-500/10 blur-[80px] rounded-full pointer-events-none group-hover:bg-pink-500/20 transition-all duration-700"></div>
        <div className="absolute bottom-0 left-0 w-64 h-64 bg-cyan-500/10 blur-[80px] rounded-full pointer-events-none group-hover:bg-cyan-500/20 transition-all duration-700"></div>

        <div className="relative z-10 text-center mb-12">
          <h2 className="text-4xl md:text-5xl font-black tracking-tighter mb-4 text-white">Let's Connect</h2>
          <p className="text-zinc-400">Have an anti-gravity idea? Drop a message and let's make it float.</p>
        </div>

        <form onSubmit={handleSubmit} className="relative z-10 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-widest text-zinc-500 ml-2">Name</label>
              <input 
                type="text" name="name" value={formData.name} onChange={handleChange} required
                className="w-full bg-zinc-900/50 border border-white/5 rounded-2xl px-5 py-4 text-white focus:outline-none focus:border-cyan-400 focus:ring-1 focus:ring-cyan-400 transition-all placeholder:text-zinc-700" 
                placeholder="Astronaut John"
              />
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold uppercase tracking-widest text-zinc-500 ml-2">Email</label>
              <input 
                type="email" name="email" value={formData.email} onChange={handleChange} required
                className="w-full bg-zinc-900/50 border border-white/5 rounded-2xl px-5 py-4 text-white focus:outline-none focus:border-purple-400 focus:ring-1 focus:ring-purple-400 transition-all placeholder:text-zinc-700" 
                placeholder="john@space.com"
              />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-xs font-bold uppercase tracking-widest text-zinc-500 ml-2">Message</label>
            <textarea 
              name="message" value={formData.message} onChange={handleChange} required rows={5}
              className="w-full bg-zinc-900/50 border border-white/5 rounded-2xl px-5 py-4 text-white focus:outline-none focus:border-pink-400 focus:ring-1 focus:ring-pink-400 transition-all resize-none placeholder:text-zinc-700" 
              placeholder="Your stellar message..."
            />
          </div>

          <motion.button 
            whileHover={{ scale: 1.02 }}
            whileTap={{ scale: 0.98 }}
            type="submit" 
            disabled={status.state === 'loading'}
            className="w-full py-4 glass-panel bg-white/5 hover:bg-white/10 text-white font-bold rounded-2xl flex items-center justify-center gap-3 transition-colors border-white/20"
          >
            {status.state === 'loading' ? 'Transmitting...' : 'Launch Message'} 
            <Send className={`w-5 h-5 ${status.state === 'loading' ? 'animate-bounce' : ''}`} />
          </motion.button>

          {status.msg && (
            <motion.div 
              initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}
              className={`p-4 rounded-xl flex items-center gap-3 ${status.state === 'success' ? 'bg-green-500/10 text-green-400 border border-green-500/20' : 'bg-red-500/10 text-red-400 border border-red-500/20'}`}
            >
              {status.state === 'success' ? <CheckCircle2 className="w-5 h-5" /> : <AlertCircle className="w-5 h-5" />}
              {status.msg}
            </motion.div>
          )}
        </form>
      </FloatingCard>
    </section>
  );
};

export default Contact;

import React from 'react';
import { motion } from 'framer-motion';
import FloatingCard from '../ui/FloatingCard';

const Experience = ({ data }) => {
  const testimonials = data?.testimonials || [
