        <h2 className="text-4xl md:text-5xl font-black tracking-tighter mb-4 text-white">Experience Timeline</h2>
        <p className="text-zinc-400 max-w-2xl mx-auto">My journey across the digital universe.</p>
      </motion.div>

      <div className="relative border-l-2 border-white/10 ml-4 md:ml-1/2 left-0 md:left-1/2 transform md:-translate-x-1/2">
