            <FloatingCard className="inline-block w-full">
              <span className="text-cyan-400 text-xs font-bold uppercase tracking-widest block mb-2">{item.year || '2026 - Present'}</span>
              <h3 className="text-xl font-bold text-white mb-3">{item.client_name}</h3>
              <p className="text-zinc-400 leading-relaxed text-sm">{item.content}</p>
            </FloatingCard>
          </motion.div>
        ))}
      </div>
    </section>
  );
};

export default Experience;

